import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Link } from 'react-router-dom';
import {
  Plus, Trash2, Edit2, Save, X, Download, TrendingUp, Package, Truck,
  AlertCircle, Settings, RotateCcw, Calendar, Users, FileText, CheckCircle,
  DollarSign, MapPin, Phone, Calculator, Search, Clock, CheckSquare, List, Grid, Box,
  Shield, LogOut, Mail
} from 'lucide-react';
import EventListView from '../components/EventListView';
import { useAppData } from '../hooks/useAppData';
import { useProductRanking } from '../hooks/useProductRanking';
import { useAuth } from '../contexts/AuthContext';
import { useSiteSettings } from '../hooks/useSiteSettings';
import { generateQuotePDF } from '../utils/generateQuotePDF';

// --- CONFIGURACIÓN Y UTILERÍAS ---

const CATEGORIAS = [
  "Mobiliario (Sillas/Mesas)",
  "Lounge & Salas",
  "Mantelería & Textiles",
  "Menaje & Vajilla",
  "Decoración & Ambientación",
  "Estructuras & Carpas",
  "Iluminación & Audio"
];

const DEFAULT_WEIGHTS = {
  rotacion: 30,
  roi: 20,
  almacenamiento: 10,
  facilidadTransporte: 10,
  costoTransporte: 15,
  durabilidad: 15
};

const DEFAULT_APP_SETTINGS = {
  defaultQuoteValidity: 15 // days
};


const formatoCOP = new Intl.NumberFormat('es-CO', {
  style: 'currency',
  currency: 'COP',
  minimumFractionDigits: 0,
  maximumFractionDigits: 0,
});

// --- CONFIGURACIÓN POR DEFECTO ---
const DEFAULT_EVENT_SETTINGS = {
  alerts: { quoteWarning: 7, eventUrgent: 15 },
  statusColors: {
    'Confirmado': 'bg-blue-100 text-blue-700',
    'Pago': 'bg-emerald-100 text-emerald-700',
    'Realizado & Pagado': 'bg-purple-100 text-purple-700',
    'Cancelado': 'bg-red-100 text-red-700',
    'Cotizado': 'bg-yellow-100 text-yellow-700'
  },
  alertColors: {
    'warning': 'bg-yellow-400',
    'urgent': 'bg-red-500'
  },
  scoreColors: {
    'joya': 'bg-green-100 text-green-800 border-green-200',
    'bueno': 'bg-blue-100 text-blue-800 border-blue-200',
    'regular': 'bg-yellow-100 text-yellow-800 border-yellow-200',
    'riesgo': 'bg-red-100 text-red-800 border-red-200',
    'perdida': 'bg-red-200 text-red-900 border-red-300'
  }
};

// --- LÓGICA DE NEGOCIO ---

// 1. Algoritmo de Puntuación (Meta-Score) RESTAURADO
const calcularMetricas = (item, pesos, scoreColors = DEFAULT_EVENT_SETTINGS.scoreColors) => {
  // A. Rentabilidad Unitaria (Predictiva)
  const margenNeto = item.precioAlquiler - (item.costoTransporte || 0);
  const paybackEventos = margenNeto > 0 ? (item.costo / margenNeto) : 999;

  // B. Puntuación ROI (Predictiva)
  let scoreROI = 0;
  if (margenNeto <= 0) scoreROI = 0;
  else if (paybackEventos <= 5) scoreROI = 10;
  else if (paybackEventos <= 10) scoreROI = 8;
  else if (paybackEventos <= 20) scoreROI = 6;
  else if (paybackEventos <= 30) scoreROI = 4;
  else scoreROI = 2;

  // C. Eficiencia Transporte (Predictiva)
  let scoreCostoTransp = 0;
  if (item.precioAlquiler > 0) {
    const ratioTransp = (item.costoTransporte || 0) / item.precioAlquiler;
    if (ratioTransp <= 0.05) scoreCostoTransp = 10;
    else if (ratioTransp <= 0.15) scoreCostoTransp = 8;
    else if (ratioTransp <= 0.30) scoreCostoTransp = 5;
    else if (ratioTransp <= 0.50) scoreCostoTransp = 2;
    else scoreCostoTransp = 0;
  }

  // D. Cálculo Meta Score Ponderado
  const scoreFacilidadTransp = item.facilidadTransporte || 5;
  const scoreRotacion = item.rotacion || 5;
  const scoreAlmacen = item.almacenamiento || 5;
  const scoreDurabilidad = item.durabilidad || 5;

  const sumaPesos = Object.values(pesos).reduce((a, b) => a + b, 0);
  const factor = sumaPesos > 0 ? (100 / sumaPesos) : 1;

  const weightedScore = (
    (scoreRotacion * (pesos.rotacion * factor) / 10) +
    (scoreROI * (pesos.roi * factor) / 10) +
    (scoreAlmacen * (pesos.almacenamiento * factor) / 10) +
    (scoreFacilidadTransp * (pesos.facilidadTransporte * factor) / 10) +
    (scoreCostoTransp * (pesos.costoTransporte * factor) / 10) +
    (scoreDurabilidad * (pesos.durabilidad * factor) / 10)
  );

  // Clasificación Meta-Score
  let clasificacion = "";
  let colorClass = "";

  // FIX: Round score explicitly before classification to handle 79.6 -> 80
  const finalScore = Math.round(weightedScore);

  if (margenNeto <= 0) { clasificacion = "⛔ Pérdida"; colorClass = scoreColors.perdida; }
  else if (finalScore >= 80) { clasificacion = "💎 Joya"; colorClass = scoreColors.joya; }
  else if (finalScore >= 60) { clasificacion = "✅ Bueno"; colorClass = scoreColors.bueno; }
  else if (finalScore >= 40) { clasificacion = "⚠️ Regular"; colorClass = scoreColors.regular; }
  else { clasificacion = "❌ Riesgo"; colorClass = scoreColors.riesgo; }

  // E. Métricas Reales (Históricas)
  const ingresosTotales = (item.vecesAlquilado || 0) * item.precioAlquiler;
  const porcentajeRecuperado = item.costo > 0 ? Math.min(100, (ingresosTotales / item.costo) * 100) : 0;
  const yaSePago = ingresosTotales >= item.costo;

  return {
    margenNeto,
    paybackEventos: paybackEventos === 999 ? ">100" : paybackEventos.toFixed(1),
    score: weightedScore.toFixed(0),
    clasificacion,
    colorClass,
    ingresosTotales,
    porcentajeRecuperado,
    yaSePago
  };
};

const DeleteConfirmationModal = ({ isOpen, onClose, onConfirm, itemName, itemType = "evento" }) => {
  const [inputValue, setInputValue] = useState("");

  useEffect(() => {
    if (isOpen) {
      // Use setTimeout to avoid synchronous state update during render if isOpen changes
      const timer = setTimeout(() => setInputValue(""), 0);
      return () => clearTimeout(timer);
    }
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
      <div className="bg-white rounded-xl shadow-2xl max-w-md w-full p-6 animate-in zoom-in-95 duration-200">
        <h3 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
          <AlertCircle className="text-red-500" /> Confirmar Eliminación
        </h3>
        <p className="text-slate-600 mb-4">
          Esta acción no se puede deshacer. Para confirmar, por favor escribe el nombre del {itemType}:
          <span className="block font-bold text-slate-800 mt-1 select-all bg-slate-100 p-1 rounded border border-slate-200">{itemName}</span>
        </p>
        <input
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          placeholder={`Escribe el nombre del ${itemType} aquí`}
          className="w-full border border-slate-300 rounded-lg p-2.5 mb-6 focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none transition"
          autoFocus
        />
        <div className="flex justify-end gap-3">
          <button
            onClick={onClose}
            className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition"
          >
            Cancelar
          </button>
          <button
            onClick={onConfirm}
            disabled={inputValue !== itemName}
            className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed transition flex items-center gap-2"
          >
            <Trash2 size={18} /> Eliminar {itemType.charAt(0).toUpperCase() + itemType.slice(1)}
          </button>
        </div>
      </div>
    </div>
  );
};

export default function WeddingRentalApp() {
  // --- ESTADOS ---
  const [activeTab, setActiveTab] = useState('inventory');
  const { user, isAdmin, signOut } = useAuth();

  const { rankingItems, saveRankingItem, deleteRankingItem } = useProductRanking();

  const {
    eventos, setEventos,
    clientes, setClientes,
    pesos: rawPesos, setPesos,
    appSettings: rawAppSettings, setAppSettings,
    eventSettings: rawEventSettings, setEventSettings,
    realInventoryItems, setRealInventoryItems,
    cotizaciones, saveCotizacionVersion, updateCotizacionStatus,
    loading
  } = useAppData();

  const { contact: siteContactSettings } = useSiteSettings();

  const pesos = rawPesos || DEFAULT_WEIGHTS;
  const eventSettings = rawEventSettings || DEFAULT_EVENT_SETTINGS;
  const appSettings = rawAppSettings || DEFAULT_APP_SETTINGS;

  // UI States
  const [showItemForm, setShowItemForm] = useState(false);
  const [showEventForm, setShowEventForm] = useState(false);
  const [showClientForm, setShowClientForm] = useState(false);
  const [showConfig, setShowConfig] = useState(false);
  const [editingItem, setEditingItem] = useState(null);
  const [editingEvent, setEditingEvent] = useState(null);
  const [editingClient, setEditingClient] = useState(null);
  const [clientSearch, setClientSearch] = useState("");
  const [deleteModalOpen, setDeleteModalOpen] = useState(false);
  const [deleteClientModalOpen, setDeleteClientModalOpen] = useState(false);
  const [eventToDelete, setEventToDelete] = useState(null);
  const [clientToDelete, setClientToDelete] = useState(null);
  const [viewMode, setViewMode] = useState('card'); // 'card' | 'list'
  const [sortConfig, setSortConfig] = useState({ key: 'score', direction: 'desc' });

  // Real Inventory States
  const [realInventorySearch, setRealInventorySearch] = useState('');
  const [realInventoryDate, setRealInventoryDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [showRealInventoryForm, setShowRealInventoryForm] = useState(false);
  const [editingRealInventoryItem, setEditingRealInventoryItem] = useState(null);
  const [deleteRealInventoryItemModalOpen, setDeleteRealInventoryItemModalOpen] = useState(false);
  const [realInventoryItemToDelete, setRealInventoryItemToDelete] = useState(null);









  /** Enriches event with client/organizer contact data and item names/thumbnails for form display */
  const enrichEventForForm = useCallback((evento) => {
    const cliente = clientes.find((c) => c.id === evento.clienteId);
    const org = clientes.find((c) => c.id === evento.organizadorId);
    const primaryContact = (c) => c?.contactos?.find((co) => co.esPrincipal) || c?.contactos?.[0] || {};
    const enriched = { ...evento };
    if (cliente) {
      const pc = primaryContact(cliente);
      enriched.cliente = cliente.nombre;
      enriched.clienteDocumento = cliente.documento ?? '';
      enriched.clienteTelefono = pc.telefono ?? '';
      enriched.clienteEmail = pc.email ?? '';
    }
    if (org) {
      const po = primaryContact(org);
      enriched.organizador = org.nombre;
      enriched.organizadorDocumento = org.documento ?? '';
      enriched.organizadorTelefono = po.telefono ?? '';
      enriched.organizadorEmail = po.email ?? '';
    }
    enriched.organizadorIgualCliente = evento.clienteId === evento.organizadorId;
    if (evento.itemsSeleccionados?.length) {
      enriched.itemsSeleccionados = evento.itemsSeleccionados.map((sel) => {
        const inv = realInventoryItems.find((i) => i.id === sel.itemId || i.id == sel.itemId);
        return inv ? { ...sel, nombre: inv.nombre, imagenUrl: inv.imagenUrl } : sel;
      });
    }
    return enriched;
  }, [clientes, realInventoryItems]);

  const handleSaveSettings = (newSettings) => {
    setEventSettings(newSettings);

  };

  const handleAlertChange = (key, value) => {
    const newSettings = {
      ...eventSettings,
      alerts: {
        ...eventSettings.alerts,
        [key]: parseInt(value) || 0
      }
    };
    handleSaveSettings(newSettings);
  };

  const handleColorChange = (status, colorClass) => {
    const newSettings = {
      ...eventSettings,
      statusColors: {
        ...eventSettings.statusColors,
        [status]: colorClass
      }
    };
    handleSaveSettings(newSettings);
  };

  const handleAlertColorChange = (type, colorClass) => {
    // Extract just the bg color part if possible, or expect full class. 
    // For simplicity, we just save the class selected from palette
    // But wait, the palette buttons give 'bg-X text-Y'. 
    // The alert bar only needs 'bg-X'. 
    // We can just use the bg part.
    const bgClass = colorClass.split(' ')[0];

    const newSettings = {
      ...eventSettings,
      alertColors: {
        ...eventSettings.alertColors, // Ensure we preserve other alerts
        [type]: bgClass
      }
    };
    handleSaveSettings(newSettings);
  };

  const handleScoreColorChange = (status, colorClass) => {
    const newSettings = {
      ...eventSettings,
      scoreColors: {
        ...eventSettings.scoreColors,
        [status]: colorClass
      }
    };
    handleSaveSettings(newSettings);
  };

  const sortedItems = useMemo(() => {
    let sortableItems = [...rankingItems];
    if (sortConfig.key) {
      sortableItems.sort((a, b) => {
        let aValue, bValue;

        if (sortConfig.key === 'score') {
          // Score is calculated on the fly, so we need to calculate it for sorting
          const scoreColors = eventSettings?.scoreColors || DEFAULT_EVENT_SETTINGS.scoreColors;
          const metricsA = calcularMetricas(a, pesos, scoreColors);
          const metricsB = calcularMetricas(b, pesos, scoreColors);
          aValue = Number(metricsA.score);
          bValue = Number(metricsB.score);
        } else if (sortConfig.key === 'paybackEventos') {
          const scoreColors = eventSettings?.scoreColors || DEFAULT_EVENT_SETTINGS.scoreColors;
          const metricsA = calcularMetricas(a, pesos, scoreColors);
          const metricsB = calcularMetricas(b, pesos, scoreColors);
          aValue = metricsA.paybackEventos === ">100" ? 999 : Number(metricsA.paybackEventos);
          bValue = metricsB.paybackEventos === ">100" ? 999 : Number(metricsB.paybackEventos);
        } else {
          aValue = a[sortConfig.key];
          bValue = b[sortConfig.key];
        }

        if (aValue < bValue) {
          return sortConfig.direction === 'ascending' ? -1 : 1;
        }
        if (aValue > bValue) {
          return sortConfig.direction === 'ascending' ? 1 : -1;
        }
        return 0;
      });
    }
    return sortableItems;
  }, [rankingItems, sortConfig, pesos, eventSettings?.scoreColors]);

  const requestSort = (key) => {
    let direction = 'ascending';
    if (sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  // Event Form State
  const [eventItemSearch, setEventItemSearch] = useState('');
  const [eventFormTab, setEventFormTab] = useState('details'); // details | quotes

  const [eventForm, setEventForm] = useState({
    id: null, nombreEvento: '',
    clienteId: '', cliente: '', clienteDocumento: '', clienteTelefono: '', clienteEmail: '',
    organizadorId: '', organizador: '', organizadorDocumento: '', organizadorTelefono: '', organizadorEmail: '', organizadorIgualCliente: true,
    fecha: '', lugar: '', direccion: '',
    estado: 'Cotizado',
    itemsSeleccionados: [], costoTransporte: 0, depositoSeguridad: 0, notas: '',
    fechaCotizacion: new Date().toISOString().split('T')[0],
    fechaValidez: '', // Will be set on open
    horaEntrega: '',
    fechaRecogida: '',
    horaRecogida: '',
    fechaPago: '', comprobantePago: '', cotizacionEnviada: false
  });



  const [sliderValues, setSliderValues] = useState({
    rotacion: 5, almacenamiento: 5, facilidadTransporte: 5, durabilidad: 5
  });

// Se removió persistencia local de localStorage

  // Check for expired quotes on load/change
  useEffect(() => {
    const today = new Date().toISOString().split('T')[0];
    const updatedEvents = eventos.map(e => {
      // Only expire if marked as sent AND past validity date
      if (e.estado === 'Cotizado' && e.cotizacionEnviada && e.fechaValidez && e.fechaValidez < today) {
        return { ...e, estado: 'Vencida' };
      }
      return e;
    });

    // Only update if changes were made to avoid infinite loop
    const hasChanges = JSON.stringify(updatedEvents) !== JSON.stringify(eventos);
    if (hasChanges) {
      setEventos(updatedEvents);
    }
  }, [eventos, setEventos]);

  useEffect(() => {
    if (showItemForm) {
      setSliderValues({
        rotacion: editingItem?.rotacion || 5,
        almacenamiento: editingItem?.almacenamiento || 5,
        facilidadTransporte: editingItem?.facilidadTransporte || 5,
        durabilidad: editingItem?.durabilidad || 5
      });
    }
  }, [showItemForm, editingItem]);

  // --- HANDLERS (Pesos & Config) ---
  const handleWeightChange = (e) => {
    const { name, value } = e.target;
    setPesos(prev => ({ ...prev, [name]: Number(value) }));
  };
  const resetWeights = () => setPesos(DEFAULT_WEIGHTS);
  const sumaPesos = Object.values(pesos).reduce((a, b) => a + b, 0);

  // --- LÓGICA DE DISPONIBILIDAD (NEW INVENTORY) ---
  const calculateAvailability = (itemId, eventoFecha, eventoFechaRecogida, excludeEventId = null) => {
    // Si no hay ítem, 0. Si no hay fecha, no podemos calcular reservas, retornar 0 o manejarlo abajo.
    if (!itemId) return 0;

    // Buscar el ítem en el inventario real
    const inventoryItem = realInventoryItems.find(i => i.id == itemId); // Loose equality
    if (!inventoryItem) return 0;

    const totalStock = inventoryItem.cantidad;

    // Función auxiliar para normalizar fechas (ignorar horas, solo comparar fechas)
    const normalizeDate = (dateStr) => {
      if (!dateStr) return null;
      if (dateStr instanceof Date) return new Date(dateStr).setHours(0, 0, 0, 0);

      try {
        // Chequear formato DD/MM/YYYY (común en Colombia)
        if (dateStr.includes('/')) {
          const parts = dateStr.split('/');
          if (parts.length === 3) {
            // Asumiendo DD/MM/YYYY
            return new Date(parts[2], parts[1] - 1, parts[0]).getTime();
          }
        }

        // Asegurar formato YYYY-MM-DD para evitar problemas de timezone
        const parts = dateStr.split('-');
        if (parts.length === 3) return new Date(parts[0], parts[1] - 1, parts[2]).getTime();
        return new Date(dateStr).getTime();
      } catch {
        return null;
      }
    };

    const startA = normalizeDate(eventoFecha);
    // Si la fecha es inválida o no existe, retornar todo el stock disponible (Fail Open)
    if (!startA && startA !== 0) return totalStock;

    // Si no hay fecha recogida, asumimos el mismo día (alquiler de 1 día)
    let endA = normalizeDate(eventoFechaRecogida);
    if (!endA || endA < startA) endA = startA;

    let reservedQuantity = 0;

    eventos.forEach(ev => {
      // Excluir el evento que estamos editando
      if (excludeEventId && ev.id == excludeEventId) return;

      const estado = ev.estado ? ev.estado.trim() : '';

      // Solo contar eventos que reservan stock
      if (['Confirmado', 'Pago', 'Realizado & Pagado'].includes(estado)) {
        const startB = normalizeDate(ev.fecha);
        let endB = normalizeDate(ev.fechaRecogida);
        if (!startB) return; // Skip invalid events
        if (!endB || endB < startB) endB = startB;

        // Chequear solapamiento (A se solapa con B)
        // Solapamiento: StartA <= EndB AND EndA >= StartB
        if (startA <= endB && endA >= startB) {
          // Loose equality per si acaso itemsSeleccionados tiene string ids
          const itemInEvent = ev.itemsSeleccionados.find(i => i.itemId == itemId);
          if (itemInEvent) {
            reservedQuantity += Number(itemInEvent.cantidad);
          }
        }
      }
    });

    return Math.max(0, totalStock - reservedQuantity);
  };

  // --- HANDLERS (Eventos) ---
  const handleSaveEvent = (e) => {
    // Check if e is present (form submit) or if called manually
    if (e && e.preventDefault) e.preventDefault();

    if (!eventForm.nombreEvento || !eventForm.clienteId || !eventForm.fecha) {
      alert("Por favor completa los campos obligatorios (*)");
      return;
    }

    // VALIDACIÓN DE STOCK para todos los estados
    for (const item of eventForm.itemsSeleccionados) {
      const available = calculateAvailability(item.itemId, eventForm.fecha, eventForm.fechaRecogida || eventForm.fecha, editingEvent?.id);
      if (Number(item.cantidad) > available) {
        const msg = `El ítem "${item.nombre ?? 'Ítem'}" supera la disponibilidad.\nSolicitado: ${item.cantidad}\nDisponible: ${available}`;
        if (['Confirmado', 'Pago', 'Realizado & Pagado'].includes(eventForm.estado)) {
          if (!confirm(`${msg}\n\n¿Deseas guardar de todos modos (Sobreventa)?`)) return;
        } else {
          alert(`${msg}\n\nPor favor ajusta la cantidad antes de guardar.`);
          return;
        }
      }
    }

    const totalAlquiler = eventForm.itemsSeleccionados.reduce((acc, i) => acc + (i.precioUnitario * i.cantidad), 0);
    const totalGeneral = totalAlquiler + Number(eventForm.costoTransporte) + Number(eventForm.depositoSeguridad);

    const nuevoEvento = {
      ...eventForm,
      id: eventForm.id || crypto.randomUUID(),
      totalAlquiler,
      totalGeneral,
      fechaCotizacion: eventForm.fechaCotizacion || new Date().toISOString().split('T')[0],
      fechaCreacion: eventForm.id ? eventForm.fechaCreacion : new Date().toISOString()
    };

    if (editingEvent) {
      const eventoAnterior = eventos.find(e => e.id === editingEvent.id);
      if (nuevoEvento.estado === 'Realizado & Pagado' && eventoAnterior.estado !== 'Realizado & Pagado') {
        actualizarRentabilidadInventarioReal(nuevoEvento.itemsSeleccionados);
      }
      setEventos(prev => prev.map(e => e.id === editingEvent.id ? nuevoEvento : e));
    } else {
      if (nuevoEvento.estado === 'Realizado & Pagado') {
        actualizarRentabilidadInventarioReal(nuevoEvento.itemsSeleccionados);
      }
      setEventos(prev => [...prev, nuevoEvento]);
    }

    setShowEventForm(false);
    setEditingEvent(null);
    resetEventForm();
  };



  const actualizarRentabilidadInventarioReal = (itemsAlquilados) => {
    setRealInventoryItems(prevItems => prevItems.map(invItem => {
      const alquilado = itemsAlquilados.find(i => i.itemId === invItem.id);
      if (alquilado) {
        return {
          ...invItem,
          veces_alquilado_total: (invItem.veces_alquilado_total || 0) + Number(alquilado.cantidad),
          ingresos_totales: (invItem.ingresos_totales || 0) + (Number(alquilado.precioUnitario) * Number(alquilado.cantidad))
        };
      }
      return invItem;
    }));
  };

  const addItemToEvent = (item, qty) => {
    let quantity = Math.max(1, Math.floor(Number(qty)));
    if (!quantity || isNaN(quantity)) return;

    const itemId = item.id ?? item.itemId;
    const itemName = item.nombre ?? realInventoryItems.find((i) => i.id === itemId || i.id == itemId)?.nombre ?? 'Ítem';

    const fechaRecogida = eventForm.fechaRecogida || eventForm.fecha;
    const available = calculateAvailability(itemId, eventForm.fecha, fechaRecogida, editingEvent?.id);

    if (available <= 0) {
      alert(`No hay disponibilidad de "${itemName}" para las fechas seleccionadas.`);
      return;
    }

    const cappedQty = Math.min(quantity, available);
    if (cappedQty < quantity) {
      alert(`Solo hay ${available} unidad(es) disponible(s) de "${itemName}" para estas fechas. Se ajustó la cantidad a ${cappedQty}.`);
      quantity = cappedQty;
    }

    const existing = eventForm.itemsSeleccionados.find(i => i.itemId === itemId || i.itemId == itemId);
    if (existing) {
      setEventForm(prev => ({
        ...prev,
        itemsSeleccionados: prev.itemsSeleccionados.map(i => (i.itemId === itemId || i.itemId == itemId) ? { ...i, cantidad: quantity } : i)
      }));
    } else {
      const inventoryItem = realInventoryItems.find(r => r.id === itemId || r.id == itemId);
      const itemToAdd = inventoryItem || item;

      setEventForm(prev => ({
        ...prev,
        itemsSeleccionados: [...prev.itemsSeleccionados, {
          itemId: itemToAdd.id,
          nombre: itemToAdd.nombre,
          cantidad: quantity,
          precioUnitario: itemToAdd.precioAlquiler
        }]
      }));
    }
  };

  const removeItemFromEvent = (itemId) => {
    setEventForm(prev => ({ ...prev, itemsSeleccionados: prev.itemsSeleccionados.filter(i => i.itemId !== itemId) }));
  };

  const resetEventForm = () => {
    setEventItemSearch('');
    setEventForm({
      id: null, nombreEvento: '',
      clienteId: '', cliente: '', clienteDocumento: '', clienteTelefono: '', clienteEmail: '',
      organizadorId: '', organizador: '', organizadorDocumento: '', organizadorTelefono: '', organizadorEmail: '', organizadorIgualCliente: true,
      fecha: '', lugar: '', direccion: '',
      estado: 'Cotizado',
      itemsSeleccionados: [], costoTransporte: 0, depositoSeguridad: 0, notas: '',
      fechaCotizacion: new Date().toISOString().split('T')[0],
      fechaValidez: '',
      horaEntrega: '',
      fechaRecogida: '',
      horaRecogida: '',
      fechaPago: '', comprobantePago: '', cotizacionEnviada: false
    });
    setEventFormTab('details');
  };

  const [clientContacts, setClientContacts] = useState([]);

  // --- HANDLERS (Eventos) ---
  // ... (handleSaveEvent, actualizarUsoInventario, etc. - staying same, need to be careful with line numbers)
  // Re-implementing handleClientSelect to check for contacts
  const handleClientSelect = (e) => {
    const clienteId = e.target.value;
    const cliente = clientes.find(c => c.id === clienteId);

    if (cliente) {
      // Find primary contact
      const primaryContact = cliente.contactos?.find(c => c.esPrincipal) || cliente.contactos?.[0] || {};

      setEventForm(prev => {
        const newState = {
          ...prev,
          clienteId: cliente.id,
          cliente: cliente.nombre,
          clienteDocumento: cliente.documento || '',
          clienteTelefono: primaryContact.telefono || '',
          clienteEmail: primaryContact.email || ''
        };
        // Auto-asignar organizador si el check está activo
        if (prev.organizadorIgualCliente) {
          newState.organizadorId = cliente.id;
          newState.organizador = cliente.nombre;
          newState.organizadorDocumento = cliente.documento || '';
          newState.organizadorTelefono = primaryContact.telefono || '';
          newState.organizadorEmail = primaryContact.email || '';
        }
        return newState;
      });
    } else {
      setEventForm(prev => ({
        ...prev,
        clienteId: '', cliente: '', clienteDocumento: '', clienteTelefono: '', clienteEmail: '',
        organizadorId: prev.organizadorIgualCliente ? '' : prev.organizadorId,
        organizador: prev.organizadorIgualCliente ? '' : prev.organizador,
        organizadorDocumento: prev.organizadorIgualCliente ? '' : prev.organizadorDocumento,
        organizadorTelefono: prev.organizadorIgualCliente ? '' : prev.organizadorTelefono,
        organizadorEmail: prev.organizadorIgualCliente ? '' : prev.organizadorEmail
      }));
    }
  };

  // --- HANDLERS (Clientes) ---
  const handleSaveClient = (e) => {
    e.preventDefault();
    const formData = new FormData(e.target);

    // Validate that at least one contact exists
    if (clientContacts.length === 0) {
      alert("Debe agregar al menos un contacto.");
      return;
    }

    const newClient = {
      id: editingClient ? editingClient.id : crypto.randomUUID(),
      nombre: formData.get('nombre'),
      tipo: formData.get('tipo'),
      documento: formData.get('documento'),
      contactos: clientContacts
    };

    if (editingClient) setClientes(prev => prev.map(c => c.id === editingClient.id ? newClient : c));
    else setClientes(prev => [...prev, newClient]);

    setShowClientForm(false);
    setEditingClient(null);
    setClientContacts([]);
  };

  // Effect to load contacts when editing
  useEffect(() => {
    if (showClientForm) {
      if (editingClient && editingClient.contactos) {
        setClientContacts(editingClient.contactos);
      } else {
        setClientContacts([]);
      }
    }
  }, [showClientForm, editingClient]);

  const addContact = () => {
    const newContact = {
      id: crypto.randomUUID(),
      nombre: "",
      telefono: "",
      email: "",
      esPrincipal: clientContacts.length === 0 // First one matches principal by default
    };
    setClientContacts([...clientContacts, newContact]);
  };

  const removeContact = (id) => {
    setClientContacts(prev => prev.filter(c => c.id !== id));
  };

  const updateContact = (id, field, value) => {
    setClientContacts(prev => prev.map(c => c.id === id ? { ...c, [field]: value } : c));
  };

  const setPrimaryContact = (id) => {
    setClientContacts(prev => prev.map(c => ({
      ...c,
      esPrincipal: c.id === id
    })));
  };

  // --- HANDLERS (Product Ranking) ---
  const handleSaveItem = (e) => {
    e.preventDefault();
    const formData = new FormData(e.target);
    const item = {
      // id is omitted for new items so Supabase generates a valid UUID
      ...(editingItem ? { id: editingItem.id } : {}),
      nombre: formData.get('nombre'),
      imageUrl: formData.get('imageUrl'),
      purchaseLink: formData.get('purchaseLink'),
      categoria: formData.get('categoria'),
      costo: Number(formData.get('costo')),
      precioAlquiler: Number(formData.get('precioAlquiler')),
      costoTransporte: Number(formData.get('costoTransporte')),
      cantidad: Number(formData.get('cantidad')),
      rotacion: Number(formData.get('rotacion')),
      almacenamiento: Number(formData.get('almacenamiento')),
      facilidadTransporte: Number(formData.get('facilidadTransporte')),
      durabilidad: Number(formData.get('durabilidad')),
      vecesAlquilado: editingItem ? editingItem.vecesAlquilado : 0,
      ingresosHistoricos: editingItem ? editingItem.ingresosHistoricos : 0,
    };

    saveRankingItem(item);
    setShowItemForm(false);
    setEditingItem(null);
  };

  const handleDeleteEvent = (evento) => {
    setEventToDelete(evento);
    setDeleteModalOpen(true);
  };

  const confirmDeleteEvent = () => {
    if (eventToDelete) {
      setEventos(prev => prev.filter(e => e.id !== eventToDelete.id));
      setDeleteModalOpen(false);
      setEventToDelete(null);
    }
  };

  const handleDeleteClient = (cliente) => {
    setClientToDelete(cliente);
    setDeleteClientModalOpen(true);
  };

  const confirmDeleteClient = () => {
    if (clientToDelete) {
      setClientes(prev => prev.filter(c => c.id !== clientToDelete.id));
      setDeleteClientModalOpen(false);
      setClientToDelete(null);
    }
  };

  // --- HANDLERS (Real Inventory) ---
  const handleSaveRealInventoryItem = (e) => {
    e.preventDefault();
    const formData = new FormData(e.target);
    const cantNueva = Number(formData.get('cantidad'));
    const costoNuevo = Number(formData.get('costo'));
    const hoy = new Date().toISOString();

    let nuevoHistorial = editingRealInventoryItem ? (editingRealInventoryItem.historialAjustes || []) : [];
    if (editingRealInventoryItem) {
      const cantAnterior = editingRealInventoryItem.cantidad || 0;
      const dif = cantNueva - cantAnterior;
      if (dif !== 0) {
        let motivo = "Ajuste manual (Compra/Entrada)";
        if (dif < 0) {
          const promptMotivo = window.prompt("Motivo de la disminución de inventario (Ej: Daño, Pérdida, Retiro, Deterioro):");
          if (promptMotivo === null || promptMotivo.trim() === '') {
            return; // Cancel the save process if user cancels prompt or leaves it empty
          }
          motivo = `Salida: ${promptMotivo.trim()}`;
        }

        nuevoHistorial = [
          {
            fecha: hoy,
            cambio: dif,
            cantidadFinal: cantNueva,
            motivo: motivo
          },
          ...nuevoHistorial
        ];
      }
    } else {
      if (cantNueva > 0) {
        nuevoHistorial = [{ fecha: hoy, cambio: cantNueva, cantidadFinal: cantNueva, motivo: "Inventario Inicial" }];
      }
    }

    const newItem = {
      id: editingRealInventoryItem ? editingRealInventoryItem.id : crypto.randomUUID(),
      nombre: formData.get('nombre'),
      categoria: formData.get('categoria'),
      marca: formData.get('marca') || '',
      linkCompra: formData.get('linkCompra') || '',
      imagenUrl: formData.get('imagenUrl') || '',
      cantidad: cantNueva,
      costo: costoNuevo,
      precioAlquiler: Number(formData.get('precioAlquiler')),
      costoTransporte: Number(formData.get('costoTransporte')),
      fechaCreacion: editingRealInventoryItem ? (editingRealInventoryItem.fechaCreacion || hoy) : hoy,
      fechaModificacion: hoy,
      historialAjustes: nuevoHistorial,
      costo_total_adquisicion: (() => {
        if (editingRealInventoryItem) {
          const cantAnterior = editingRealInventoryItem.cantidad || 0;
          const dif = cantNueva - cantAnterior;
          const historico = editingRealInventoryItem.costo_total_adquisicion || (cantAnterior * editingRealInventoryItem.costo) || 0;
          if (dif > 0) {
            return historico + (dif * costoNuevo); // Compra
          }
          return historico;
        }
        return cantNueva * costoNuevo;
      })(),
      veces_alquilado_total: editingRealInventoryItem ? (editingRealInventoryItem.veces_alquilado_total || 0) : 0,
      ingresos_totales: editingRealInventoryItem ? (editingRealInventoryItem.ingresos_totales || 0) : 0,
    };

    if (editingRealInventoryItem) {
      setRealInventoryItems(prev => prev.map(i => i.id === editingRealInventoryItem.id ? newItem : i));
    } else {
      setRealInventoryItems(prev => [...prev, newItem]);
    }

    setShowRealInventoryForm(false);
    setEditingRealInventoryItem(null);
  };

  const handleDeleteRealInventoryItem = (item) => {
    setRealInventoryItemToDelete(item);
    setDeleteRealInventoryItemModalOpen(true);
  };

  const confirmDeleteRealInventoryItem = () => {
    if (realInventoryItemToDelete) {
      setRealInventoryItems(prev => prev.filter(i => i.id !== realInventoryItemToDelete.id));
      setDeleteRealInventoryItemModalOpen(false);
      setRealInventoryItemToDelete(null);
    }
  };

  // --- RENDERIZADO ---

  if (loading) {
    return <div className="flex h-screen items-center justify-center text-slate-500">Cargando datos del sistema...</div>;
  }

  return (
    <div className="flex min-h-screen bg-gray-50 text-slate-800 font-sans">

      {/* SIDEBAR NAVIGATION */}
      <aside className="fixed left-0 top-0 h-screen w-64 bg-slate-900 text-white flex flex-col z-50">
        <Link
          to="/"
          className="p-6 flex items-center gap-3 border-b border-slate-800 hover:bg-slate-800 transition group"
          title="Ir al inicio"
        >
          <TrendingUp className="text-emerald-400 group-hover:text-emerald-300 transition" />
          <span className="font-bold text-lg tracking-tight group-hover:text-white transition">RentEvent</span>
        </Link>

        <nav className="flex-1 py-6 px-3 space-y-2">
          {[
            { id: 'inventory', label: 'Ranking Productos', icon: TrendingUp },
            { id: 'real_inventory', label: 'Inventario', icon: Box },
            { id: 'events', label: 'Eventos', icon: Calendar },
            { id: 'clients', label: 'Clientes', icon: Users },
          ].map(item => (
            <button
              key={item.id}
              onClick={() => { setActiveTab(item.id); setShowConfig(false); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
            >
              <item.icon size={20} />
              <span className="font-medium">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800 space-y-2">
          {isAdmin && (
            <Link
              to="/admin"
              className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-amber-400 hover:bg-slate-800 hover:text-amber-300 transition font-medium text-sm"
            >
              <Shield size={18} />
              <span>Panel de Admin</span>
            </Link>
          )}
          <button
            onClick={signOut}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-slate-500 hover:bg-slate-800 hover:text-red-400 transition font-medium text-sm"
          >
            <LogOut size={18} />
            <span>Cerrar Sesión</span>
          </button>
          <div className="bg-slate-800 rounded-xl p-3 mt-2">
            <p className="text-xs text-slate-400 mb-0.5">Versión 2.0</p>
            <p className="text-xs font-bold text-slate-500">© 2026 Rentevent</p>
          </div>
        </div>
      </aside>

      {/* CONTENIDO PRINCIPAL */}
      <div className="ml-64 w-full min-h-screen flex flex-col">

        {/* TOPBAR GLOBAL */}
        <header className="bg-white border-b border-slate-200 h-16 flex items-center justify-between px-8 sticky top-0 z-40 shadow-sm">
          <h1 className="text-xl font-bold text-slate-800 capitalize">
            {activeTab === 'inventory' ? 'Ranking de Productos' : activeTab === 'real_inventory' ? 'Control de Inventario' : activeTab === 'events' ? 'Gestión de Eventos' : 'Directorio de Clientes'}
          </h1>
          <div className="flex items-center gap-4">
            <button
              onClick={() => setShowConfig(true)}
              className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition relative"
              title="Configuración de Página"
            >
              <Settings size={22} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-red-400 rounded-full border-2 border-white"></span>
            </button>
            <div
              className="w-8 h-8 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-700 font-bold text-xs ring-2 ring-indigo-50 uppercase"
              title={user?.email}
            >
              {user?.email?.substring(0, 2) ?? '??'}
            </div>
          </div>
        </header>

        {/* DRAWER CONFIGURACIÓN (CONTEXTO GLOBAL) */}
        {showConfig && (
          <>
            <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-50" onClick={() => setShowConfig(false)}></div>
            <div className="fixed right-0 top-0 h-screen w-96 bg-white shadow-2xl z-[60] p-6 overflow-y-auto animate-in slide-in-from-right duration-300">
              <div className="flex justify-between items-center mb-8">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                  <Settings className="text-indigo-600" /> Configuración
                </h2>
                <button onClick={() => setShowConfig(false)} className="text-slate-400 hover:text-red-500"><X size={24} /></button>
              </div>

              {/* CONTENIDO DINÁMICO SEGÚN PÁGINA */}
              {activeTab === 'events' ? (
                <div className="space-y-6">
                  <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 mb-6">
                    <p className="text-sm text-indigo-800 font-medium">Configuración de alertas y colores para eventos.</p>
                  </div>

                  {/* ALERTAS */}
                  <h3 className="font-bold text-slate-700 flex items-center gap-2 border-b pb-2">
                    <AlertCircle size={18} className="text-orange-500" /> Alertas de Fecha
                  </h3>
                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-slate-600">Validez Cotización (días):</span>
                      <input
                        type="number"
                        min="1"
                        max="365"
                        value={appSettings.defaultQuoteValidity}
                        onChange={(e) => setAppSettings(prev => ({ ...prev, defaultQuoteValidity: Number(e.target.value) }))}
                        className="w-16 p-1 border border-slate-300 rounded text-center text-sm"
                      />
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-slate-600">Cotización Antigua (días):</span>
                      <input
                        type="number"
                        min="1"
                        max="365"
                        value={eventSettings.alerts.quoteWarning}
                        onChange={(e) => handleAlertChange('quoteWarning', e.target.value)}
                        className="w-16 p-1 border border-slate-300 rounded text-center text-sm"
                      />
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-slate-600">Evento Próximo (días):</span>
                      <input
                        type="number"
                        min="1"
                        max="365"
                        value={eventSettings.alerts.eventUrgent}
                        onChange={(e) => handleAlertChange('eventUrgent', e.target.value)}
                        className="w-16 p-1 border border-slate-300 rounded text-center text-sm"
                      />
                    </div>
                  </div>

                  {/* ALERT COLORS - Using a simpler palette since it's just a line */}
                  <h3 className="font-bold text-slate-700 flex items-center gap-2 border-b pb-2 pt-4">
                    <AlertCircle size={18} className="text-red-500" /> Colores de Alerta
                  </h3>
                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-slate-600">Alerta Advertencia (Amarillo):</span>
                      <div className="flex gap-1">
                        {['bg-yellow-400', 'bg-orange-400', 'bg-amber-400', 'bg-lime-400'].map(bg => (
                          <button
                            key={bg}
                            onClick={() => handleAlertColorChange('warning', bg)}
                            className={`w-6 h-6 rounded-full border border-slate-200 ${bg} ${(eventSettings.alertColors?.warning || 'bg-yellow-400') === bg ? 'ring-2 ring-offset-1 ring-indigo-500' : ''}`}
                          />
                        ))}
                      </div>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-slate-600">Alerta Urgente (Rojo):</span>
                      <div className="flex gap-1">
                        {['bg-red-500', 'bg-rose-500', 'bg-pink-500', 'bg-purple-500'].map(bg => (
                          <button
                            key={bg}
                            onClick={() => handleAlertColorChange('urgent', bg)}
                            className={`w-6 h-6 rounded-full border border-slate-200 ${bg} ${(eventSettings.alertColors?.urgent || 'bg-red-500') === bg ? 'ring-2 ring-offset-1 ring-indigo-500' : ''}`}
                          />
                        ))}
                      </div>
                    </div>
                  </div>

                  {/* COLORES ESTADO */}
                  <h3 className="font-bold text-slate-700 flex items-center gap-2 border-b pb-2 pt-4">
                    <Settings size={18} className="text-indigo-500" /> Colores de Estado
                  </h3>
                  <div className="space-y-3">
                    {['Confirmado', 'Pago', 'Realizado & Pagado', 'Cancelado', 'Cotizado', 'Vencida'].map(status => (
                      <div key={status} className="flex flex-col gap-1">
                        <span className="text-xs font-semibold text-slate-500">{status}</span>
                        <div className="flex flex-wrap gap-1">
                          {[
                            'bg-slate-100 text-slate-700', 'bg-red-100 text-red-700', 'bg-orange-100 text-orange-700', 'bg-amber-100 text-amber-700',
                            'bg-yellow-100 text-yellow-700', 'bg-lime-100 text-lime-700', 'bg-green-100 text-green-700', 'bg-emerald-100 text-emerald-700',
                            'bg-teal-100 text-teal-700', 'bg-cyan-100 text-cyan-700', 'bg-sky-100 text-sky-700', 'bg-blue-100 text-blue-700',
                            'bg-indigo-100 text-indigo-700', 'bg-violet-100 text-violet-700', 'bg-purple-100 text-purple-700', 'bg-fuchsia-100 text-fuchsia-700',
                            'bg-pink-100 text-pink-700', 'bg-rose-100 text-rose-700'
                          ].map(colorClass => (
                            <button
                              key={colorClass}
                              onClick={() => handleColorChange(status, colorClass)}
                              className={`w-5 h-5 rounded-full border border-slate-200 ${colorClass.split(' ')[0]} ${eventSettings.statusColors[status] === colorClass ? 'ring-2 ring-offset-1 ring-indigo-500' : ''}`}
                              title={colorClass}
                            />
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ) : activeTab === 'inventory' ? (
                <div className="space-y-6">
                  <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 mb-6">
                    <p className="text-sm text-indigo-800 font-medium">Estás configurando el algoritmo de valoración de inventario.</p>
                  </div>

                  <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-slate-700">Pesos del Algoritmo</h3>
                    <button onClick={resetWeights} className="text-xs text-indigo-600 hover:underline flex items-center gap-1"><RotateCcw size={12} /> Restaurar</button>
                  </div>

                  <div className="space-y-5">
                    {[
                      { key: 'rotacion', label: 'Rotación', desc: 'Demanda estimada' },
